package com.example.demo.ui;import com.example.demo.mapper.VentaMapper;import com.example.demo.services.*;import com.vaadin.flow.component.button.Button;import com.vaadin.flow.component.html.*;import com.vaadin.flow.component.orderedlayout.VerticalLayout;import com.vaadin.flow.router.*;import java.text.NumberFormat;import java.util.Locale;
@Route("ticket/:id")@PageTitle("Ticket | Franco")public class TicketView extends VerticalLayout implements BeforeEnterObserver{
    private static final NumberFormat MONEY=NumberFormat.getCurrencyInstance(Locale.of("es","AR"));private final VentaService ventas;private final ConfiguracionComercioService config;
    public TicketView(VentaService ventas,ConfiguracionComercioService config){this.ventas=ventas;this.config=config;addClassName("ticket-page");}
    @Override public void beforeEnter(BeforeEnterEvent event){if(!UserSession.isLoggedIn()){event.rerouteTo(LoginView.class);return;}Long id=Long.valueOf(event.getRouteParameters().get("id").orElseThrow());var sale=ventas.detalle(id).map(VentaMapper::toDTO).orElseThrow();var c=config.obtener();Div ticket=new Div();ticket.addClassName("thermal-ticket");ticket.getStyle().set("--ticket-width",c.anchoTicket()+"mm");ticket.add(new H2(c.nombre()));if(c.razonSocial()!=null)ticket.add(new Paragraph(c.razonSocial()));if(c.cuit()!=null)ticket.add(new Paragraph("CUIT: "+c.cuit()));if(c.direccion()!=null)ticket.add(new Paragraph(c.direccion()));ticket.add(new Hr(),new Paragraph("Comprobante: "+sale.numeroComprobante()),new Paragraph("Fecha: "+sale.fecha()),new Hr());sale.items().forEach(i->ticket.add(new Paragraph(i.nombreProducto()+" · "+i.cantidadMostrada()+("PESO".equals(i.unidadVenta())?" kg":" u")+" × "+MONEY.format(i.precioUnitario())+" = "+MONEY.format(i.subtotal()))));if(sale.descuento().signum()>0)ticket.add(new Paragraph("Descuento: -"+MONEY.format(sale.descuento())));ticket.add(new Hr(),new H3("TOTAL "+MONEY.format(sale.total())),new Paragraph("Pago: "+sale.medioPago()));if(sale.vuelto().signum()>0)ticket.add(new Paragraph("Vuelto: "+MONEY.format(sale.vuelto())));if(c.mensajeTicket()!=null)ticket.add(new Hr(),new Paragraph(c.mensajeTicket()));Button print=new Button("Imprimir",e->getUI().ifPresent(ui->ui.getPage().executeJs("window.print()")));print.addClassName("no-print");add(ticket,print);}
}
